scwin.btn_save_onClick = async function (e) {
  let j = 0;
  let z = 0;
  scwin.debugCheck++;
  if (ds_workTime.getTotalRow() == 0 && ds_Present.getTotalRow() == 0) {
    $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_001, "실적과 기능직 휴무"));
    return;
  }
  if (ds_Present.getModifiedIndex().length == 0 && ds_workTime.getModifiedIndex().length == 0) {
    scwin.debugCheck++;
    //기능직 휴무 그리드에 수정사항이나 추가사항이 없다면,
    //인원을 선택했는지(ds_staff)  Check
    for (i = 0; i < ds_staff.getTotalRow(); i++) {
      if (ds_staff.getCellData(i, "checkBox") == "T") {
        j = j + 1;
        scwin.gfixedArrangeYn = ds_staff.getCellData(i, "fixedArrangeYn");
      }
    }
    if (j == 0) {
      $c.win.alert($p, "인원을 선택 후 저장하십시오.");
      return;
    }
  } else {
    if (ds_Present.getTotalRow() > 0 || ds_Present.getModifiedIndex().length >= 1) {
      let stDt = "";
      let endDt = "";

      //기능직휴무 그리드(gr_vacation), 필수입력항목 null 체크
      if (!(await $c.gus.cfValidate($p, [gr_vacation]))) {
        return;
      }
      for (z = 0; z < ds_Present.getTotalRow(); z++) {
        stDt = ds_Present.getCellData(z, "vacaStDt");
        endDt = ds_Present.getCellData(z, "vacaEndDt");

        // 휴무시작일자가 종료일자보다 이후일 경우
        if (!$c.gus.cfIsAfterDate($p, stDt, endDt, false)) {
          $c.win.alert($p, MSG_CM_ERR_039);
          return false;
        }
      }
      if (ds_Present.getModifiedIndex().length >= 1) {
        //저장하시겠습니까?
        if (await $c.win.confirm($p, MSG_CM_CRM_001)) {
          await scwin.saveCheckedStaff();
          scwin.pos_groupCode = gr_staff.getFocusedRowIndex(); // 저장 전의 위치 저장
          // sbm_main.userData1="noError";
          await $c.sbm.execute($p, sbm_saveVacation);
        }
      }
    }

    //근무시간 유무
    if (ds_workTime.getTotalRow() > 0) {
      for (i = 0; i < ds_staff.getTotalRow(); i++) {
        if (ds_staff.getCellData(i, "checkBox") == "T") {
          j = j + 1;
          scwin.gfixedArrangeYn = ds_staff.getCellData(i, "fixedArrangeYn");
        }
      }
      if (j == 0) {
        $c.win.alert($p, "인원을 선택 후 저장하십시오.");
        return;
      }
      if (ds_workTime.getTotalRow() == 1 && ds_workTime.getCellData(0, "workClsCd") == "N") {
        $c.win.alert($p, "근무구분을 업무간휴무만 입력하여 저장할 수 없습니다 .");
        return;
      }

      //근무구분별 필수항목 첵크(근무구분이 배치인 경우 작업지시번호,작업단계 필수) 
      for (i = 0; i < ds_workTime.getTotalRow(); i++) {
        if (ds_workTime.getCellData(i, "workClsCd") == "A" && scwin.gfixedArrangeYn != "1") {
          if (ds_workTime.getCellData(i, "wrkIndictNo") == "") {
            $c.win.alert($p, "근무구분이 배치인 경우 작업지시번호는 필수입니다.");
            gr_workTime.setFocusedCell(i, "wrkIndictNo");
            return;
          }
          if (ds_workTime.getCellData(i, "wrkStpCd") == "") {
            $c.win.alert($p, "근무구분이 배치인 경우 작업단계는 필수입니다.");
            gr_workTime.setFocusedCell(i, "wrkStpCd");
            return;
          }
          if (ds_workTime.getCellData(i, "commWrkScYn") == "1" && ds_workTime.getCellData(i, "commWrkScStd") == 0) {
            $c.win.alert($p, "원당작업의 경우 적용시간이 필요합니다..");
            gr_workTime.setFocusedCell(i, "commWrkScStd");
            return;
          }
          if (ds_workTime.getCellData(i, "rainScYn") == "1" && ds_workTime.getCellData(i, "rainScStd") == 0) {
            $c.win.alert($p, "우천작업의 경우 적용시간이 필요합니다..");
            gr_workTime.setFocusedCell(i, "rainScStd");
            return;
          }
          if (ds_workTime.getCellData(i, "snowScYn") == "1" && ds_workTime.getCellData(i, "snowScStd") == 0) {
            $c.win.alert($p, "설천작업의 경우 적용시간이 필요합니다..");
            gr_workTime.setFocusedCell(i, "snowScStd");
            return;
          }
          if (ds_workTime.getCellData(i, "gangWrkYn") == "1" && ds_workTime.getCellData(i, "gangWrkStd") == 0) {
            $c.win.alert($p, "Gang작업의 경우 적용시간이 필요합니다..");
            gr_workTime.setFocusedCell(i, "gangWrkStd");
            return;
          }
          if (ds_workTime.getCellData(i, "odrReqYn") == "1" && ds_workTime.getCellData(i, "odrReqStd") == 0) {
            $c.win.alert($p, "오더작업의 경우 적용시간이 필요합니다..");
            gr_workTime.setFocusedCell(i, "odrReqStd");
            return;
          }
          if (ds_workTime.getCellData(i, "extendWrkScYn") == "1" && ds_workTime.getCellData(i, "extendWrkScStd") == 0) {
            $c.win.alert($p, "원당작업의 경우 적용시간이 필요합니다..");
            gr_workTime.setFocusedCell(i, "extendWrkScStd");
            return;
          }
          if (ds_workTime.getCellData(i, "holiWrkScYn") == "1" && ds_workTime.getCellData(i, "holiWrkScStd") == 0) {
            $c.win.alert($p, "명절작업의 경우 적용시간이 필요합니다..");
            gr_workTime.setFocusedCell(i, "holiWrkScStd");
            return;
          }
        }
      }

      //작업시간 
      if (!(await $c.gus.cfValidate($p, [gr_workTime]))) {
        return;
      }
      if (!scwin.f_checkVacationDate()) {
        return;
      }
      for (i = 0; i < ds_workTime.getTotalRow(); i++) {
        let workSt = ds_workTime.getCellData(i, "workStDt") + ds_workTime.getCellData(i, "workStHh");
        let workEnd = ds_workTime.getCellData(i, "workEndDt") + ds_workTime.getCellData(i, "workEndHh");
        let startDate = workSt.trim();
        let endDate = workEnd.trim();
        let totalDate = (endDate - startDate) / 1000 / 60 / 60;
        if (totalDate >= 24) {
          $c.win.alert($p, "작업일이 하루가 넘습니다.");
        }
      }
      if (ds_workTime.getModifiedIndex().length >= 1) {
        if (await $c.win.confirm($p, MSG_CM_CRM_001)) {
          scwin.debugCheck++;
          await scwin.saveCheckedStaff();
          scwin.debugCheck++;
          scwin.pos_groupCode = gr_staff.getFocusedRowIndex(); // 저장 전의 위치 저장
          // sbm_saveWork.userData1="noError";
          await $c.sbm.execute($p, sbm_saveWork);
        }
      }
    }
  }
};
