//-------------------------------------------------------------------------
// 실적미등록인원 선택 f_SelNotRegist
//-------------------------------------------------------------------------
scwin.btn_Select_onClick = async function (e) {
  let bModify = false;
  if (ds_staff.getTotalRow() == 0) {
    return;
  }
  for (i = 0; i < ds_workTime.getTotalRow(); i++) {
    if (ds_workTime.getRowStatus(i) != "R") {
      bModify = true;
      break;
    }
  }

  //변경된 사항이 있으면
  if (bModify) {
    if (!(await $c.win.confirm($p, MSG_CM_CRM_005))) {
      return;
    }
  }
  gr_staff.checkAll("checkBox", "F");
  ds_workTime.removeAll();
  ds_staff.undoAll();
  let row = 0;
  for (i = 0; i < ds_staff.getTotalRow(); i++) {
    if (ds_staff.getCellData(i, "resultRegYn") == "N" && ds_staff.getCellData(i, "arrangeContGb") != "1") {
      // 미배치와 사유있는 휴무일때 (SQL에서 정의)
      if (row == 0) {
        row = i;
      }
      ds_staff.setCellData(i, "checkBox", "T");
    }
  }
  if (row == 0) {
    return;
  }
  scwin.cmdKnd = "";
  gr_staff.setFocusedCell(row, 1);
  // ds_staff.setRowPosition(row);
  // await scwin.f_retrieveDetail(row);
  let staffNo = ds_staff.getCellData(row, "staffNo");
  row = ds_workTime.insertRow();
  ds_workTime.setCellData(row, "staffNo", staffNo);
  ds_workTime.setCellData(row, "workDt", scwin.ed_wrkDt);
  ds_workTime.setCellData(row, "workStDt", scwin.ed_wrkDt);
  ds_workTime.setCellData(row, "workStHh", "0800");
  ds_workTime.setCellData(row, "workEndDt", scwin.ed_wrkDt);
  ds_workTime.setCellData(row, "workEndHh", "1700");
  ds_workTime.setCellData(row, "workClsCd", "U");
  ds_workTime.setCellData(row, "dtlTskCntnCd", "");
  gr_workTime.setHeaderColor("column15", "black"); //wrkIndictNo
  gr_workTime.setHeaderColor("column9", "black"); // wrkStpCd

  gr_workTime.setColumnReadOnly("wrkIndictNo", true);
  gr_workTime.setColumnReadOnly("wrkStpCd", true);
  gr_workTime.setColumnReadOnly("shiftClsCd", true);
  gr_workTime.setFocusedCell(0, "dtlTskCntnCd");
  scwin.setTskCntnFilter("U");
};
scwin.setTskCntnFilter = function (value) {
  if (ds_workTime.getRowCount() == 0) {
    return;
  }
  scwin.v_workClsCd = ds_workTime.getCellData(ds_workTime.getRowPosition(), "workClsCd");
  ds_tskCntn.clearFilter();
  ds_tskCntn.setColumnFilter({
    type: 'row',
    colIndex: 'upperCd',
    key: value,
    condition: 'and',
    exactMatch: true
  });
};
scwin.ds_wkrStp_filter = function () {
  ds_wkrStp.clearFilter();
  if (ds_workTime.getRowCount() == 0) {
    return;
  }
  if (scwin.v_workClsCd == "") {
    return;
  }
  if (scwin.v_workClsCd == "Y") {
    ds_wkrStp.setColumnFilter({
      type: 'row',
      colIndex: 'upperWrkStpCd',
      key: "03",
      condition: 'and',
      exactMatch: true
    });
  } else if (scwin.v_workClsCd == "P") {
    ds_wkrStp.setColumnFilter({
      type: 'row',
      colIndex: 'upperWrkStpCd',
      key: "01",
      condition: 'and',
      exactMatch: true
    });
  } else if (scwin.v_workClsCd == "T") {
    ds_wkrStp.setColumnFilter({
      type: 'row',
      colIndex: 'upperWrkStpCd',
      key: "03",
      condition: 'and',
      exactMatch: true
    });
  } else {
    ds_wkrStp.setColumnFilter({
      type: 'row',
      colIndex: 'wrkStpCd',
      key: "004",
      condition: 'and',
      exactMatch: true
    });
    return;
  }
};

//-------------------------------------------------------------------------
// 실적 유무 체크
//-------------------------------------------------------------------------
scwin.f_staffValChk = async function (row) {
  let bModify = false; //변경된 사항
  let resultCheckCnt = 0; //실적이 있는것을 첵크했는지
  let checkCnt = 0;
  let isCommonStaff = false; // 상용화 인원 여부 
  let arrangeContYN = false; //배치가능 인원 여부
  let gfixedArrangeYn = "";

  //실적이 있는것을 check했는지 	
  for (i = 0; i < ds_staff.getTotalRow(); i++) {
    if (ds_staff.getCellData(i, "checkBox") == "T" && ds_staff.getCellData(i, "resultRegYn") == "Y") {
      resultCheckCnt = resultCheckCnt++;
    }
    if (ds_staff.getCellData(i, "checkBox") == "T") {
      checkCnt++;
    }
  }
  if (checkCnt >= 1) {
    gfixedArrangeYn = ds_staff.getCellData(row, "fixedArrangeYn");
  }
  let resultRegYn = ds_staff.getCellData(row, "resultRegYn");
  if (ds_staff.getCellData(row, "checkBox") == "T") {
    let checkedRows = ds_staff.getMatchedIndex("checkBox", "T");
    let fixedCnt = 0; // 고정배치(1)
    let nonFixedCnt = 0; // 미배치(0)

    for (let i = 0; i < checkedRows.length; i++) {
      let val = ds_staff.getCellData(checkedRows[i], "fixedArrangeYn");
      if (val == "1") {
        fixedCnt++;
      } else {
        nonFixedCnt++;
      }
    }
    if (fixedCnt > 0 && nonFixedCnt > 0) {
      ds_staff.setCellData(row, "checkBox", "F");
      await $c.win.alert($p, "고정배치인원은 일배치 및 미배치 인원과 동시에 선택할 수 없습니다.");
      return;
    }

    // asis 로직을 따라가려했으나 안먹어서 바꿈
    // //고정배치인원선택시
    // if (gfixedArrangeYn == "1") {
    //     //고정배치가 아닌 미배치 인원일 경우
    //     if (ds_staff.getMatchedIndex("fixedArrangeYn", "0").length > 1 && ds_staff.getMatchedIndex("checkBox", "T").length > 1) {
    //         ds_staff.setCellData(row, "checkBox", "F");

    //         await $c.win.alert("고정배치인원은 일배치 및 미배치 인원과 동시에 선택할 수 없습니다.");
    //         return;
    //     } 
    // } else if (gfixedArrangeYn != "1"){
    //     //고정배치가 아닌 미배치 인원일 경우
    //     if(ds_staff.getMatchedIndex("fixedArrangeYn", "1").length > 1 && ds_staff.getMatchedIndex("checkBox", "T").length > 1) {
    //         ds_staff.setCellData(row, "checkBox", "F");
    //         await $c.win.alert("고정배치인원은 일배치 및 미배치 인원과 동시에 선택할 수 없습니다.");
    //         return;
    //     }
    // }

    // 상용화 인원 유무
    if (isCommonStaff && Number(ds_staff.getCellData(row, "totalShiftCnt")) > 0) {
      $c.win.alert($p, "상용화 인원 " + ds_staff.getCellData(row, "staffNm") + "(" + ds_staff.getCellData(row, "staffNo") + " )에 대해 이번달 투입된 총 Shift수는 " + ds_staff.getCellData(row, "totalShiftCnt") + " Shift 입니다.");
    }
    //최초인경우
    if (checkCnt == 1) {
      gfixedArrangeYn = ds_staff.getCellData(row, "fixedArrangeYn");
      //변경된 사항이 있으면
      if (bModify) {
        if (!(await $c.win.confirm($p, MSG_CM_CRM_005))) {
          ds_staff.setCellData(row, "checkBox", "T");
          return;
        }
      }
      await scwin.f_retrieveDetail(row);
    } else {
      //실적있는것을 선택
      if (resultRegYn == "Y") {
        //이미 실적있는것을 선택했을경우
        if (Number(resultCheckCnt) > 1) {
          ds_staff.setCellData(row, "checkBox", "F");
          $c.win.alert($p, "이미 실적이 등록된 인원에 대한 실적 수정 및 삭제는 한명씩 가능합니다.");
          return;
        } else if (Number(resultCheckCnt) == 1) {
          //변경된 사항이 있으면
          if (bModify) {
            if (!(await $c.win.confirm($p, MSG_CM_CRM_005))) {
              ds_staff.setCellData(row, "checkBox", "T");
              return;
            }
          }
          await scwin.f_retrieveDetail(row);
        }
      } else {//실적없는것을 선택한경우
      }
    }
  } else {
    //uncheck시

    //변경된 사항이 있으면
    if (bModify) {
      if (!(await $c.win.confirm($p, MSG_CM_CRM_005))) {
        ds_staff.setCellData(row, "checkBox", "T");
        return;
      }
    }
    ds_staff.undoRow(row);

    //선택한게 없으면 모두 clear
    //if(checkCnt == 0 || ResultCheckCnt == 0){
    if (checkCnt == 0) {
      ds_Present.removeAll();
      scwin.updateGrVacationCellInputType();
      ds_workTime.removeAll();
    }

    //실적있는 것을 uncheck한 경우 기존 조회된 데이타 삭제된다는 error message 
    if (ds_staff.getCellData(row, "resultRegYn") == "Y") {
      for (i = 0; i < ds_staff.getTotalRow(); i++) {
        if (ds_staff.getCellData(i, "checkBox") == "T") {
          await scwin.f_retrieveDetail(i);
          break;
          // return;
        }
      }
    }
  }
};

