scwin.btn_deleteRow_onclick = function (e) {
  let row = gr_vacation.getFocusedRowIndex();
  if (row >= 0) {
    if (ds_Present.getRowStatus(row) === "C") {
      ds_Present.removeRow(row);
    } else {
      ds_Present.deleteRow(row);
      gr_vacation.setFocusedCell(row, 0);
    }
  }
  scwin.updateTotalRows2();
};

//-------------------------------------------------------------------------
// 근무시간 그리드 Clear 클릭시
//-------------------------------------------------------------------------
scwin.btn_Clear_onClick = async function (e) {
  let bModify = false;
  for (i = 0; i < ds_workTime.getTotalRow(); i++) {
    if (ds_workTime.getRowStatus(i) != "R") {
      bModify = true;
      break;
    }
  }
  if (!bModify) {
    for (i = 0; i < ds_Present.getTotalRow(); i++) {
      if (ds_Present.getRowStatus(i) != "R") {
        bModify = true;
        break;
      }
    }
  }

  //변경된 사항이 있으면
  if (bModify) {
    if (await $c.win.confirm($p, MSG_CM_CRM_005)) {
      gr_staff.checkAll("checkBox", "F");
      ds_workTime.removeAll();
    }
    return;
  }
  gr_staff.checkAll("checkBox", "F");
  ds_workTime.removeAll();
  ds_staff.undoAll();
  scwin.cmdKnd = "";
};

