//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function (inObj, pairObj, disGubun, isCode) {
  // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  if (!$c.gus.cfCanOpenPopup($p, inObj, pairObj)) return;

  // 짝이 되는 오브젝트의 값 제거
  $c.gus.cfClearPairObj($p, pairObj);

  // 검색어 세팅
  var pVal = $c.gus.cfGetValue($p, inObj);

  // inObj가 코드 필드일 경우 팝업
  if (isCode == null || isCode == true) {
    await scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'F');
  } else {
    // inObj가 코드명 필드일 경우 팝업
    await scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
  }
};
//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {
  // 선언부
  switch (disGubun) {
    case 1:
      //점소
      udc_bran.cfCommonPopUp(scwin.udc_bran_callBackFunc, pCode, pName, pClose, null, null, null, null, null, null, null, null, null); //점소
      break;
    case 2:
      {
        if (!(await $c.gus.cfValidate($p, [ed_branCd]))) {
          return;
        }
        let rtnList = await scwin.f_openStaffNoPopUp(pCode, pName, "", "T", "1");
        if (rtnList != null) {
          ed_staffNo.setValue(rtnList[2]); //사원코드
          ed_staffNm.setValue(rtnList[3]); //사원명
          return;
        } else {
          ed_staffNo.setValue(""); //사원코드
          ed_staffNm.setValue(""); //사원명
        }
        break;
      }
  }
};
scwin.f_openStaffNoPopUp = async function (pCode, pName, arrangeContYN, pClose, flag) {
  let arrParam = new Array();
  arrParam[0] = pCode; //사번
  arrParam[1] = pName; //사원명
  arrParam[2] = ed_branCd.getValue(); //점소코드
  arrParam[3] = ed_branNm.getValue(); //점소명
  arrParam[4] = ""; //작업장코드
  arrParam[5] = acb_occptypeCd.getValue(); //직종  (정규직/계약직)
  arrParam[6] = acb_dtlOccptypeCd.getValue(); //상세직종코드 
  arrParam[7] = ""; //직급
  arrParam[8] = ""; //작업일
  arrParam[9] = arrangeContYN; //배치가능여부
  arrParam[10] = pClose; //WINDOW CLOSE 여부
  arrParam[11] = flag; //상세직종Flag

  // 팝업 옵션 설정
  let options = {
    id: "staffNoPopUp",
    type: "browserPopup",
    popupName: "인력검색",
    width: 700,
    height: 530
  };

  //상세화면 호출
  return await $c.win.openPopup($p, "/ui/ds/op/rscconfirm/manpwrrscconfirm/op_103_01_10p.xml", options, arrParam);
};
scwin.f_openGridStaffNoPopUp = async function (row, pCode, pName, pClose) {
  if (!$c.gus.cfValidate($p, [ed_branCd])) {
    return;
  }
  let rtnList = await scwin.f_openStaffNoPopUp(pCode, pName, "Y", pClose, "3");
  if (rtnList != null) {
    ds_Present.setCellData(row, "staffNo", rtnList[2]); //사원코드
    ds_Present.setCellData(row, "staffNm", rtnList[3]); //사원명
    ds_Present.setCellData(row, "lodeptNm", rtnList[7]); //물류부서
    ds_Present.setCellData(row, "occptypeNm", rtnList[1]); //직종		    
    ds_Present.setCellData(row, "dtlOccptypeNm", rtnList[9]); //상세직종
  }
};

