//-------------------------------------------------------------------------
// 저장 완료시
//-------------------------------------------------------------------------
scwin.sbm_saveWork_submitDone = async function (e) {
  try {
    if (e.responseJSON.resultDataSet[0].Code < 0) {
      // await $c.win.alert(e.responseJSON.resultDataSet[1].Msg);
      return; //onFail
    }
    scwin.cmdKnd = "save";
    scwin.debugCheck++;
    await $c.win.alert($p, MSG_CM_INF_001); // 성공적으로 저장하였습니다.

    ds_workTime.setJSON([]);
    dma_searchStaff.set("branCd", ed_branCd.getValue()); //점소
    dma_searchStaff.set("occptypeCd", acb_occptypeCd.getValue()); //직종
    dma_searchStaff.set("dtlOccptypeCd", acb_dtlOccptypeCd.getValue()); //상세직종
    dma_searchStaff.set("staffNo", ed_staffNo.getValue()); //인원
    dma_searchStaff.set("wrkDt", ica_qryWrkDt.getValue()); //일자

    scwin.ed_wrkDt = ica_qryWrkDt.getValue();

    // await scwin.btn_retrieve_onClick();

    let k = 0;
    for (let staffNo of scwin.checkStaffArray) {
      let matched = ds_staff.getMatchedIndex("staffNo", staffNo, true);
      if (matched.length >= 1) {
        k = matched;
        ds_staff.setCellData(k, "checkBox", "T");
        break;
      }
    }

    // ds_staff.setJSON([]);
    await scwin.f_retrieveDetail(k);
    // scwin.gr_staff_onClick(k , "", "");

    await $c.sbm.execute($p, sbm_searchStaff);

    // scwin.gr_staff_onClick(k, "", "");
  } catch (e) {
    console.log("sbm_saveAcctRecvBdebt_submitdone : " + e);
  }
};
scwin.sbm_saveVacation_submitdone = async function (e) {
  try {
    if (e.responseJSON.resultDataSet[0].Code < 0) {
      await $c.win.alert($p, e.responseJSON.resultDataSet[1].Msg);
      return; //onFail
    }
    await $c.sbm.execute($p, sbm_searchVacation);
  } catch (e) {
    console.log("sbm_saveAcctRecvBdebt_submitdone : " + e);
  }
};

//-------------------------------------------------------------------------
