//-------------------------------------------------------------------------
scwin.updateGrVacationCellInputType = function () {
  let idx = 0;
  let rowCnt = Math.min($c.num.parseInt($p, spa_totalRows2.getValue(), 0), ds_Present.getTotalRow());
  for (; idx < rowCnt; ++idx) {
    gr_vacation.setCellInputType(idx, "vacaStDt", {
      "inputType": "text"
    });
  }
  rowCnt = ds_Present.getTotalRow();
  for (; idx < rowCnt; ++idx) {
    gr_vacation.setCellInputType(idx, "vacaStDt", {
      "inputType": "calendar",
      options: {}
    });
  }
};
scwin.sbm_searchVacation_submitdone = function (e) {
  scwin.updateTotalRows2();
};
scwin.updateTotalRows2 = function () {
  spa_totalRows2.setValue(ds_Present.getTotalRow());
  scwin.updateGrVacationCellInputType();
};

