//-------------------------------------------------------------------------
scwin.searchWork_Suc = function (e) {
  // 삭제해봐
  for (i = 0; i < ds_workTime.getTotalRow(); i++) {
    gr_workTime.refreshRow(i);
  }
  gr_workTime.setFocusedCell(0, 1);
  scwin.updateTotalRows2();
};

/**
 * method
 * @name comboValueLabelFormatter1
 * @description 콤보 '[value]label'로 표시
 * @param {String} label
 * @returns {String}
 */
scwin.comboValueLabelFormatter1 = function (label) {
  let idx = label.indexOf(":");
  if (idx < 0) {
    return label;
  }
  return "[" + label.substring(0, idx).trim() + "]" + label.substring(idx + 1).trim();
};

